window.__QUIZ_DATA__=[{"id":"objective>Physics>2019>1","subject":"Physics","year":"2019","type":"Objective","topic":"RECTILINEAR ACCELERATION : CONCEPT OF ACCELERATION/DECELERATION","question":"The time rate of increase in velocity is called","images":[],"options":{"A":"force","B":"momentum","C":"acceleration","D":"speed"},"answer":"C","explanation":"The time rate of increase in velocity is called acceleration. It is a measure of how quickly an object changes its velocity. Force is the interaction that, when unopposed, will change the motion of an object. Momentum is the product of the mass and velocity of an object. Speed is the magnitude of velocity.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2019>2","subject":"Physics","year":"2019","type":"Objective","topic":"SCALARS AND VECTORS : CONCEPT OF VECTORS","question":"Which of the following quantities is a vector?","images":[],"options":{"A":"Volume","B":"Momentum","C":"Energy","D":"Speed"},"answer":"B","explanation":"A vector quantity is a quantity that has both magnitude and direction. Momentum is a vector quantity because it has both magnitude (the amount of momentum) and direction (the direction in which the object is moving). Volume, Energy, and Speed are scalar quantities because they only have magnitude and no direction.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2019>3","subject":"Physics","year":"2019","type":"Objective","topic":"CONSERVATION OF ENERGY","question":"In an elastic collision, momentum is conversed as well as","images":[],"options":{"A":"velocity","B":"kinetic energy","C":"potential energy","D":"speed"},"answer":"B","explanation":"In an elastic collision, there is no net lo in kinetic energy of the system and the momentum is conserved.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>4","subject":"Physics","year":"2019","type":"Objective","topic":"ELECTROMAGNETIC FIELD : LENZ\u2019S LAW","question":"The induced current in a coil always flows in a direction so as to oppose the change that causes it. This statement is known as","images":[],"options":{"A":"Coulomb's law","B":"Lenz's law","C":"Faraday's law","D":"Ampere's law"},"answer":"B","explanation":"Lens  law states that an induced current in a coil always flows in a direction such that the current opposes the change that induced it .","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>5","subject":"Physics","year":"2019","type":"Objective","topic":"ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES","question":"Which of the following instruments can be used to compare the magnitudes of charges on two given bodies.","images":[],"options":{"A":"Electrophorus","B":"Ebonite rod","C":"Gold-leaf electroscope","D":"Proof planes"},"answer":"C","explanation":"A Gold-leaf electroscope is an instrument that can be used to compare the magnitudes of charges on two given bodies. It works on the principle that like charges repel each other. When a charged object is brought near the cap of the electroscope, the leaves repel each other and diverge. The degree of divergence gives a measure of the amount of charge.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>6","subject":"Physics","year":"2019","type":"Objective","topic":"WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD","question":"A body of mass 2 kg is released from a point 100m above the ground. Calculate its kinetic energy 80m from the point of release.","images":[],"options":{"A":"1600J","B":"900J","C":"600J","D":"200J"},"answer":"A","explanation":"Kinetic energy 80m from point of release = potential energy from 80m high to ground = Mgh = 2 \u00d7 10 \u00d7 80 = 1600J","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>7","subject":"Physics","year":"2019","type":"Objective","topic":"TYPES OF WAVES : WAVE MOTION","question":"Which of the following waves is not mechanical?","images":[],"options":{"A":"Waves in pipes","B":"Water waves","C":"Radio waves","D":"Sound waves"},"answer":"C","explanation":"Mechanical waves require a medium through which to travel. Examples of mechanical waves include sound waves, water waves, and waves in pipes. Radio waves, on the other hand, are electromagnetic waves. They can travel through the vacuum of space, and do not require a medium. Therefore, radio waves are not mechanical waves.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>8","subject":"Physics","year":"2019","type":"Objective","topic":"SIMPLE HARMONIC MOTION : SIMPLE HARMONIC MOTION (S.H.M)","question":"A loaded spring is set in simple harmonic motion. The force that tends to restore the load to its equilibrium position is","images":[],"options":{"A":"adhesive","B":"elastic","C":"frictional","D":"gravitational"},"answer":"B","explanation":"This force is commonly referred to as the \"restoring force,\" and it's provided by the elasticity of the spring. As the spring is stretched or compressed away from its equilibrium position, it exerts a force in the opposite direction, trying to bring the load (mass) back to its equilibrium position. This force is directly proportional to the displacement from the equilibrium position according to Hooke's Law, which is characteristic of simple harmonic motion.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>9","subject":"Physics","year":"2019","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"Which of the following cases cannot produce total internal reflection? A light ray travelling from","images":[],"options":{"A":"glass of water.","B":"kerosene to air.","C":"air to water.","D":"water to ice."},"answer":"C","explanation":"Total internal reflection occurs when a light wave is moving from a denser to less dense medium at an incidence angle > critical angle. Air to water, is moving from less dense to denser medium, total internal reflection cannot occur.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>10","subject":"Physics","year":"2019","type":"Objective","topic":"HEAT ENERGY : HEAT TRANSFER","question":"The vacuum in a thermoflask reduces heat loss resulting from","images":[],"options":{"A":"radiation only","B":"conduction and convection only","C":"radiation and convection only","D":"conduction only"},"answer":"B","explanation":"A thermoflask is designed to reduce heat loss through conduction and convection. The vacuum in a thermoflask prevents heat transfer by conduction and convection because these processes require a medium (solid, liquid, or gas) to occur. Radiation can still occur in a vacuum, but the flask's reflective lining helps to minimize this.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>11","subject":"Physics","year":"2019","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"The diagram above represents an experimental set-up for verifying","images":["data:image/png;base64,"],"options":{"A":"lens formula","B":"refraction laws","C":"reflection laws","D":"mirror formula"},"answer":"D","explanation":"The generated image depicts a reflective surface, suggesting the presence of a mirror.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>12","subject":"Physics","year":"2019","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : FIRST LAW","question":"Which of the following statements about a moving object is correct?","images":[],"options":{"A":"When accelerating, the resultant force acting on it must be equal to zero.","B":"There must always be a non-zero resultant force acting on it.","C":"At a steady velocity, the resultant force acting on it must be equal to zero.","D":"At a steady velocity, the air resistance must be equal to zero."},"answer":"C","explanation":"At a steady velocity, there is no acceleration, therefore, the resultant force is zero. for a moving object  at steady velocity , the result force acting on it must be equal to zero","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>13","subject":"Physics","year":"2019","type":"Objective","topic":"SIMPLE A.C. CIRCUITS : POWER","question":"If the efficiency of a transformer is 100%, which of the following equations would be correct?","images":[],"options":{"A":"NpEp = NsEs","B":"NsIp = NpIs","C":"NsIs = NpIp","D":"IpEs = IsEp"},"answer":"C","explanation":"voltage current relationship for an ideal transformer   EpEs=NpNs=IsIp","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>14","subject":"Physics","year":"2019","type":"Objective","topic":"MAGNETIC FIELD : MAGNETIZATION AND DEMAGNETIZATION","question":"A freshly demagnetized bar magnet is placed in the East-West direction to ensure that","images":[],"options":{"A":"the molecular magnets remain randomly arranged","B":"the molecular magnets are properly aligned","C":"it is affected by the earth's magnetic field","D":"the magnetic domains are within the earth's field"},"answer":"A","explanation":"By placing a freshly demagnetized bar magnet in the East-West direction, we are ensuring that the magnetic domains remain randomly arranged and that the magnet remains demagnetized.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>15","subject":"Physics","year":"2019","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"Which of the following graphs of a charge Q against potential difference V across capacitor is correct?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"B","explanation":"Charge varies directly with potential difference.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>16","subject":"Physics","year":"2019","type":"Objective","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"A small amount of air is introduced into the vacuum above the mercury in a mercury barometer tube. The mercury level goes down because the air molecules","images":[],"options":{"A":"heat the mercury and make it to expand.","B":"increase the pressure above the mercury.","C":"cool the mercury and make it to contract.","D":"decrease the pressure above the mercury."},"answer":"B","explanation":"When air is introduced into the vacuum above the mercury in a barometer tube, it increases the pressure above the mercury. This increased pressure pushes down on the mercury, causing the mercury level to go down. This is based on the principle that pressure is force per unit area, and in this case, the force is exerted by the air molecules on the mercury.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>17","subject":"Physics","year":"2019","type":"Objective","topic":"HEAT ENERGY : LATENT HEAT","question":"Calculate the quantity of heat needed to change the temperature of 60g of ice at 0\u00b0C to 80\u00b0C.  [Specific latent heat of fusion of ice = 3.36 \u00d7 105 Jkg-1, Specific heat capacity of water = 4.2 \u00d7 103 Jkg-1K-1]","images":[],"options":{"A":"4.80 kJ","B":"20.16 kJ","C":"40.32 kJ","D":"22.17 kJ"},"answer":"C","explanation":"Total Heat = Heat required to heat ice from solid at 0\u00b0C to liquid at 0\u00b0C + Heat required to heat liquid water from 0\u00b0C to 80\u00b0C  \u21d2 m. \u0394Hfus + M . C . \u0394T  Convertingmasstokilogram=60g\u00d71kg1000g = 0.06kg,  substituting, we have   0.06 \u00d7 3.36 \u00d7 105 + 4.2 \u00d7 103 \u00d7 0.06 \u00d7 (90 - 0)  20,160 + 20,160  \u21d2 40,320J  \u21d2 40.32KJ","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>18","subject":"Physics","year":"2019","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"The wire of a platinum resistance thermometer has a resistance of 3.5\u03a9 at 0\u00b0C and 10.5 \u03a9 at 100\u00b0C. Calculate the temperature of the wire when its resistance is 7.5\u03a9.","images":[],"options":{"A":"78\u00b0C","B":"25\u00b0C","C":"36\u00b0C","D":"57\u00b0C"},"answer":"D","explanation":"7.5 - 3.510.5 - 3.5=x - 0\u00b0C100 - 0  =47=x100  x=4\u00d71007 = 57\u00b0C","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>19","subject":"Physics","year":"2019","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : SPEED, FREQUENCY AND WAVELENGTH","question":"A transverse pulse of frequency 9 Hz travels 4.5m in 0.6s. Calculate the wavelength of the pulse.","images":[],"options":{"A":"3.33 m","B":"0.30 m","C":"0.83 m","D":"1.20 m"},"answer":"C","explanation":"Velocity=speedtime=4.50.6=7.5ms  Velocity = \u03bbF  substituting, we have   7.5 = 9\u03bb  \u03bb=7.59=0.83m","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>20","subject":"Physics","year":"2019","type":"Objective","topic":"SOUND WAVES : SPEED OF SOUND","question":"In which of the following media is speed of sound the least?","images":[],"options":{"A":"Air","B":"Brass","C":"Water","D":"Wood"},"answer":"A","explanation":"The speed of sound is least in air compared to brass, water, and wood. This is because sound travels faster in solids and liquids than in gases. The particles in solids and liquids are closer together than in gases, which allows the sound waves to be transmitted more quickly.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2019>21","subject":"Physics","year":"2019","type":"Objective","topic":"PROPERTIES OF WAVES : REFLECTION~~PROPERTIES OF WAVES : REFRACTION~~PROPERTIES OF WAVES : DIFFRACTION","question":"Which of the following characteristics of waves can a ripple tank be used to demonstrate?  I. Reflection  II. Refraction  III. Diffraction","images":[],"options":{"A":"I, II and III","B":"II and III only","C":"I and III only","D":"I and II only"},"answer":"A","explanation":"A ripple tank can be used to show the basic properties of a wave including diffraction, reflection, refraction and interference.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>22","subject":"Physics","year":"2019","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF ENERGY","question":"Which of the following graphs gives the correct relationship between energy and mass when mass is converted to energy.","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"B","explanation":"When mass is converted to energy, for example potential energy it increases proportionally.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>23","subject":"Physics","year":"2019","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"An 800kg car moving at 80 kmhr-1 collides with a 1200kg car moving at 40kmhr-1 in the same direction. If the cars stick together, calculate their common velocity.","images":[],"options":{"A":"60 kmhr-1","B":"8 kmhr-1","C":"40 km hr-1","D":"56 km hr-1"},"answer":"D","explanation":"M1U1 + M2U2 = (M1 + M2)V  substituting  800 \u00d7 80 + 1200 \u00d7 40 = (1200, + 800)V  64,000 + 48,000 = 2000V  112,000 = 2,000V  V=112,0002000 = 56 km hr-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>24","subject":"Physics","year":"2019","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"The mass of a load is doubled while the force acting on it is halved. The resulting acceleration of the load is","images":[],"options":{"A":"quadrupled.","B":"quartered.","C":"halved.","D":"doubled."},"answer":"B","explanation":"F = Ma  Therefore, a (acceleration) = F/M  when M becomes 2M  and F becomes 1/2 F  taking F and M as unity, we have  a=1/22=12\u00d712=14","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>25","subject":"Physics","year":"2019","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"The maximum and minimum thermometer reads the","images":[],"options":{"A":"maximum temperature during the day and the minimum temperature at night at all times.","B":"maximum temperature at night and minimum temperature during the day from the last reset.","C":"maximum temperature at night and minimum temperature during the day at all times.","D":"maximum temperature during the day and minimum temperature at night from the last reset."},"answer":"D","explanation":"A maximum and minimum thermometer reads the maximum and minimum temperature since last reset, with the current temperature reading.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>26","subject":"Physics","year":"2019","type":"Objective","topic":"ELECTRIC FIELD : PRODUCTION OF ELECTRIC CURRENT","question":"An a.c. generator can be converted to a d.c. generator by replacing the","images":[],"options":{"A":"commutator with an armature.","B":"armature with a commutator.","C":"commutator with slip rings.","D":"slip rings with a commutator."},"answer":"D","explanation":"An AC generator can be converted into a DC generator by replacing the slip rings with a commutator. A commutator is a rotary electrical switch in certain types of electric motors and electrical generators that periodically reverses the current direction between the rotor and the external circuit. In a DC generator, it allows the current to flow in one direction, converting the alternating current (AC) into direct current (DC).","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>27","subject":"Physics","year":"2019","type":"Objective","topic":"MAGNETIC FIELD : MAGNETIZATION AND DEMAGNETIZATION","question":"Which of the following statements is the correct reason for using soft iron in making the armature of an electric bell?","images":[],"options":{"A":"It is a diamagnetic material.","B":"It loses its magnetism readily.","C":"It is not easily magnetized.","D":"It retains its magnetism for a long time."},"answer":"B","explanation":"Soft iron is used in the armature of an electric bell because it loses its magnetism readily. This property is known as low retentivity. When the electric current is switched off, the soft iron does not remain magnetized, which allows the bell to stop ringing.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>28","subject":"Physics","year":"2019","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"The diagram above illustrates a meter bridge circuit under balanced condition. Determine the value of x.","images":["data:image/png;base64,"],"options":{"A":"50 cm","B":"10.0 cm","C":"28.6 cm","D":"57.2 cm"},"answer":"A","explanation":"R1R2=x(100-x)  22=x100-x  100 = 2x  x = 50cm","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>29","subject":"Physics","year":"2019","type":"Objective","topic":"ELECTRIC FIELD : STORAGE OF CHARGES","question":"Which of the following devices is used for storing electric charges?","images":[],"options":{"A":"Transformer","B":"Ammeter","C":"Potentiometer","D":"Capacitor"},"answer":"D","explanation":"A capacitor is a device used to store an electric charge, consisting of one or more pairs of conductors separated by an insulator.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2019>30","subject":"Physics","year":"2019","type":"Objective","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"An electron of mass 9.1 \u00d7 10-31 kg moves with a speed of 2.0 \u00d7 106 ms-1 round the nucleus of an atom in a circular path of radius 6.1 \u00d7 10-11m.  Use the information to answer this question.    Determine the angular speed of the electron.","images":[],"options":{"A":"3.28 \u00d7 1016 rad s-1","B":"8.55 \u00d7 103 rad s-1","C":"9.11 \u00d7 1013 rad s-1","D":"5.22 \u00d7 1015 rad s-1"},"answer":"A","explanation":"V = r\u03c9  \u03c9=Vr  substituting for V and r, we have,  =2.0 \u00d7 1066.1 \u00d7 10-11=3.28\u00d71016rads-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>31","subject":"Physics","year":"2019","type":"Objective","topic":"MOTION : SIMPLE IDEAS OF CIRCULAR MOTION","question":"An electron of mass 9.1 \u00d7 10-31 kg moves with a speed of 2.0 \u00d7 106 ms-1 round the nucleus of an atom in a circular path of radius 6.1 \u00d7 10-11m.  Use the information to answer this question.  Calculate the centripetal force acting on the electron.","images":[],"options":{"A":"7.7 \u00d7 10-47 N","B":"6.0 \u00d7 10-8 N","C":"3.0 \u00d7 10-14 N","D":"1.3 \u00d7 10-26 N"},"answer":"B","explanation":"F=mv2r  substituting,  F=9.1 \u00d7 10-31 \u00d7 (2.0 \u00d7 106)26.1 \u00d7 10-11 = 6.0 \u00d7 10-8 N","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>32","subject":"Physics","year":"2019","type":"Objective","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"A device consumes 100W of power when connected to a 120V source. Calculate its resistance.","images":[],"options":{"A":"1.2\u03a9","B":"12,000.0\u03a9","C":"20.0\u03a9","D":"144.0\u03a9"},"answer":"D","explanation":"P=V2R  Therefore,   R=V2P  substituting for V and P, we have  =120\u00d7120100=144.0\u03a9","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>33","subject":"Physics","year":"2019","type":"Objective","topic":"PROPERTIES OF WAVES : REFRACTION","question":"Which property of a wave remains constant when the wave travels from one medium into another?","images":[],"options":{"A":"Amplitude","B":"Wavelength","C":"Velocity","D":"Frequency"},"answer":"D","explanation":"When a wave travels from one medium to another, its frequency remains constant. This is because the frequency of a wave is determined by the source of the wave, not the medium in which it travels. Therefore, the correct answer is option 4.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>34","subject":"Physics","year":"2019","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"The anomalous expansion of water occurs in the range","images":[],"options":{"A":"0\u00b0C to 100\u00b0C","B":"0\u00b0C to 4\u00b0C","C":"4\u00b0C to 100\u00b0C","D":"-4\u00b0C to 0\u00b0C"},"answer":"B","explanation":"The anomalous expansion of water occurs in the range of 0\u00b0C to 4\u00b0C. This is because water expands when it is cooled from 4\u00b0C to 0\u00b0C, which is unusual as most substances contract when cooled. This is known as the anomalous expansion of water.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>35","subject":"Physics","year":"2019","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"A ray of light travelling from a rectangular glass block of refractive index 1.5 into air strikes the block at an angle of incidence of 30\u00b0. Calculate its angle of refraction.","images":[],"options":{"A":"48.6\u00b0","B":"19.5\u00b0","C":"20.0\u00b0","D":"45.0\u00b0"},"answer":"B","explanation":"Sin\u03b8ASin\u03b8B=nBnA=sin301.5  =0.51.5  Sin\u03b8ASin\u03b8B=1.5 = sin-1 ( 1/3 )  Sin30Sin\u03b8B=1.5 = 19.5\u00b0","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>36","subject":"Physics","year":"2019","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"A rectangular piece of iron measuring 4cm by 3cm at 20\u00b0C is heated until its temperature increases by 100\u00b0C. Calculate the new area of the metal.  [Linear expansivity of iron is 1.2 \u00d7 10-5K-1]","images":[],"options":{"A":"12.0144 cm2","B":"12.0346 cm2","C":"12.0288 cm2","D":"12.0173 cm2"},"answer":"C","explanation":"A2 = A1(1 + \u03b2\u03b8)  Substituting,  A1 = 4cm \u00d7 3cm = 12cm2  \u03b8 = 100 - 20 = 80\u00b0C  \u03b2 = 2 \u00d7 linear expansivity (2 \u00d7 \u03b1) = 2 \u00d7 1.2 \u00d7 10-5k-1  \u21d2 2.4 \u00d7 10-5k-1  substituting,  A2 = 12 (1 + 2.4 \u00d7 10-5 \u00d7 80) = 12.0288 cm2","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>37","subject":"Physics","year":"2019","type":"Objective","topic":"GRAVITATIONAL FIELD : NEWTON\u2019S LAW OF GRAVITATION","question":"Two bodies of masses 3.0kg and 2.0kg are separated by a distance of 50cm. Calculate the force of attraction between them.  [G = 6.67 \u00d7 10-11 Nm2kg-2]","images":[],"options":{"A":"1.6 \u00d7 10-9N","B":"1.3 \u00d7 103N","C":"2.3 \u00d7 103N","D":"5.0 \u00d7 10 N"},"answer":"A","explanation":"F=GmMr2  50cm\u21d250\u00d71100m=0.5m (converting cm to m)  F=6.67 \u00d7 10-11 \u00d7 3 \u00d72(0.5)2  F=6.67 \u00d7 10-11 \u00d7 60.25  F = 1.6 \u00d7 10-9N","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>38","subject":"Physics","year":"2019","type":"Objective","topic":"MOTION : SIMPLE IDEAS OF CIRCULAR MOTION","question":"The diagram above illustrates an object moving in a circular path at constant speed. Which of the arrows indicates the direction of linear velocity?","images":["data:image/png;base64,"],"options":{"A":"Z","B":"X","C":"Y","D":"W"},"answer":"A","explanation":"The direction of linear velocity is always tangential to the circular path, when performing circular motion.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2019>39","subject":"Physics","year":"2019","type":"Objective","topic":"HEAT ENERGY : TEMPERATURE AND ITS MEASUREMENT","question":"Which of the following thermometers is used to measure the temperature of the human body?","images":[],"options":{"A":"Thermocouple","B":"Alcohol-in-glass thermometer","C":"Gas thermometer","D":"Platinum resistance thermometer"},"answer":"B","explanation":"The Alcohol-in-glass thermometer is used to measure the temperature of the human body because it is safe, easy to use, and gives accurate readings at the temperature range of the human body.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2019>40","subject":"Physics","year":"2019","type":"Objective","topic":"PRODUCTION AND PROPAGATION OF WAVES : FREQUENCY (F), WAVELENGTH(\ud835\udecc), PERIOD (T) AND VELOCITY (V)","question":"In the diagram above, the time taken to trace a wave between P and Q is","images":["data:image/png;base64,"],"options":{"A":"2 periods","B":"1 period","C":"1 1/2 periods","D":"1 1/4 periods"},"answer":"C","explanation":"From P to Q, we count 1 1/2 circle which takes 1 1/2 period to cover.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>41","subject":"Physics","year":"2019","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS","question":"Which of the following materials does not serve as a safety device in electrical circuits?","images":[],"options":{"A":"Connecting wires","B":"Earth wire","C":"Fuse","D":"Switch"},"answer":"A","explanation":"The Connecting wires do not serve as a safety device in electrical circuits. The other options, Earth wire, Fuse, and Switch, all serve as safety devices.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2019>42","subject":"Physics","year":"2019","type":"Objective","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"Which of the following liquids has the highest surface tension?","images":[],"options":{"A":"Soapy water","B":"Cold water","C":"Hot water","D":"Oily water"},"answer":"B","explanation":"Surface tension is the property of a liquid that allows it to resist an external force. It is seen in the phenomena that cause a liquid in small amounts to form spheres, which minimize surface area. Cold water has the highest surface tension among the given options. This is because surface tension decreases with temperature. So, cold water has higher surface tension than hot water. Soapy water and oily water have lower surface tension due to the presence of surfactants that disrupt the cohesive forces between the water molecules.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>43","subject":"Physics","year":"2019","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS","question":"The nucleon and proton numbers of a neutral atom of an element are 238 and 92 respectively. Determine the number of neutrons in the atom.","images":[],"options":{"A":"119","B":"330","C":"165","D":"146"},"answer":"D","explanation":"nucleon number = Number of protons + Number of Neutrons   Number of neutrons = 238 - 92  \u21d2 146 neutrons.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>44","subject":"Physics","year":"2019","type":"Objective","topic":"HEAT ENERGY : HUMIDITY, RELATIVE HUMIDITY AND DEW POINT","question":"An instrument used to measure relative humidity is the","images":[],"options":{"A":"hygrometer","B":"hydrometer","C":"pyrometer","D":"manometer"},"answer":"A","explanation":"Relative humidity is a measure of the amount of water vapor present in air expressed as a percentage of the amount needed for saturation at the same temperature. It is measured using a hygrometer. A hydrometer is used to measure the specific gravity (relative density) of liquids; a pyrometer is used to measure high temperatures; and a manometer is used to measure pressure.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>45","subject":"Physics","year":"2019","type":"Objective","topic":"MOTION : DISTANCE/DISPLACEMENT-TIME GRAPH","question":"The area under a velocity-time graph represents","images":[],"options":{"A":"speed","B":"acceleration","C":"moment","D":"distance"},"answer":"D","explanation":"The area under a velocity-time graph represents the displacement or distance covered. This is because the area under the graph is calculated by multiplying velocity (y-axis) by time (x-axis), which gives the distance.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>46","subject":"Physics","year":"2019","type":"Objective","topic":"STRUCTURE OF THE ATOM : MODELS OF THE ATOM","question":"Which of the following statements about a neutral atom is correct? The","images":[],"options":{"A":"core is composed of electrons and protons.","B":"number of electrons is equal to that of neutrons.","C":"number of neutrons is equal to that of protons.","D":"number of protons is equal to that of electrons."},"answer":"D","explanation":"In a neutral atom, the number of protons is equal to the number of electrons. This is because protons carry a positive charge and electrons carry a negative charge. In a neutral atom, the total positive charge from the protons is balanced by the total negative charge from the electrons.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2019>47","subject":"Physics","year":"2019","type":"Objective","topic":"PROPERTIES OF WAVES : POLARIZATION","question":"Which of the following properties is not exhibited by sound waves?","images":[],"options":{"A":"Diffraction.","B":"Polarization.","C":"Interference.","D":"Reflection."},"answer":"B","explanation":"Sounds are longitudinal waves, meaning they oscillate parallel to the direction of their motion. Hence, cannot be polarized.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>48","subject":"Physics","year":"2019","type":"Objective","topic":"STRUCTURE OF THE ATOM : PHOTOELECTRIC EFFECT","question":"When ultraviolet light is incident on certain metallic surfaces, particles are emitted. These particles are called","images":[],"options":{"A":"positrons.","B":"protons.","C":"photoelectrons.","D":"photons."},"answer":"C","explanation":"When light of a particle wavelength (ultraviolet light) falls on some metallic surface photoelectrons are emitted.","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>49","subject":"Physics","year":"2019","type":"Objective","topic":"STRUCTURE OF THE ATOM : MODELS OF THE ATOM","question":"Niels Bohr drew certain conclusions about the structure of the atom. Which of the following statements is one of those conclusions?","images":[],"options":{"A":"The allowed orbits contain the same number of electrons.","B":"Within an atom, there are certain allowed orbits.","C":"All of the orbits represent the same amount of energy.","D":"The orbit with the least energy is farthest from the nucleus."},"answer":"B","explanation":"Niels Bohr's model of the atom, also known as the Bohr model, proposed that electrons move in specific, discrete orbits around the nucleus. These orbits are 'allowed' in the sense that they are stable and an electron in such an orbit will not radiate energy. Hence, the correct answer is 'Within an atom, there are certain allowed orbits.'","marks":"1","difficulty":"3"},{"id":"objective>Physics>2019>50","subject":"Physics","year":"2019","type":"Objective","topic":"HEAT ENERGY : MELTING POINT","question":"The graph above illustrates the variation of temperature \u03b8 with time t for a solid that is being heated. Which processes take place at segments P and Q respectively?","images":["data:image/png;base64,"],"options":{"A":"Freezing and vaporization","B":"Evaporation and solidification","C":"Melting and boiling","D":"Condensation and evaporation"},"answer":"C","explanation":"During melting and boiling the temperature remains constant, what is taken in is known as latent heat.","marks":"1","difficulty":"2"}];